    // Create a vector to store the header data with the appropriate size
    std::vector<uint8_t> header_data(header_size);

    // Use the copy method of hexi::file_buffer to copy header data without advancing read pointer
    buffer.copy(header_data.data(), header_size);

    // Return the vector containing the header preview
    return header_data;
}
