#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm> // For std::min

template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(const hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_preview) {
    // Determine the actual number of bytes to copy (minimum of requested and available)
    size_t actual_bytes = std::min(bytes_to_preview, buffer.size());

    // Create a destination vector with appropriate size
    std::vector<uint8_t> destination(actual_bytes);

    // Use the copy method to copy data without advancing read pointer
    buffer.copy(destination.data(), actual_bytes);

    return destination;
}
```

